import React from "react";
import styles from "./card-bg.module.css";
import Title from "../../../title";

const CardBg: React.FC = () => {
  return (
    <div className={styles.card_bg}>
      <Title level="h1" className={styles.title}>
        🌱 The nature candle
      </Title>
    </div>
  );
};

export default CardBg;
